35	}
36	
37	function closeWsClient(ws) {
38	  return new Promise((resolve) => {
39	    if (ws.readyState === WebSocket.CLOSED) return resolve();
40	    ws.once('close', resolve);
41	    ws.close();
42	  });
43	}
