    await page.getByRole('button', { name: 'Updated Title' }).click();
    await page.getByLabel('Edit assignee').click();
    await page.getByLabel('Assignee').fill('Alice');
    await page.getByLabel('Save').click();
    await page.getByLabel('Close').click();
