    await page.getByRole('button', { name: '+ Add card' }).click();
    await expect(page.getByLabel('Title')).toBeVisible();
  });

  test('submitting creates a card in the Ready column', async ({ page }) => {
    await page.goto('/');
    await page.getByRole('button', { name: '+ Add card' }).click();
    await page.getByLabel('Title').fill('My E2E Card');
    await page.getByRole('button', { name: 'Add card' }).click();
