    const cB   = createCard({ title: 'B', column: 'ready' });
    const mover = createCard({ title: 'Mover', column: 'done' });

    // Force positions to have a gap of 0.0005 (< 0.001)
    const db = getDb();
    db.prepare('UPDATE cards SET position = ? WHERE id = ?').run(1.0,    cA.id);
